mapper.select:
SELECT a.id, a.title, a.summary, COALESCE(NULLIF(a.cover_image, ''), '/upload/default.png') AS cover_image, a.status, a.view_count, a.like_count, a.favorite_count, a.comment_count, a.is_top, a.create_time, c.name AS category_name, u.nickname AS author_name FROM article a LEFT JOIN category c ON a.category_id = c.id LEFT JOIN user u ON a.author_id = u.id WHERE a.deleted = 0
AND a.category_id = #{categoryId}
AND (a.title LIKE CONCAT('%', #{keyword}, '%') OR a.summary LIKE CONCAT('%', #{keyword}, '%') OR a.tags LIKE CONCAT('%', #{keyword}, '%'))
AND a.status = #{status}
ORDER BY a.is_top DESC, a.create_time DESC
